import{ac as s,b as r,A as n,d as e,u as o,E as c,w as d,F as h}from"./vendor.b0b4d815.js";const p=s(`<h1>About i2c.ninja</h1><p>i2c.ninja is a static website that aim to visualize sensor readings with <a href="https://sourcekit.cc">sourcekit\xAE</a> ATiic.</p><p>It is powered by <a href="https://developer.mozilla.org/en-US/docs/Web/API/Web_Serial_API">Web Serial API</a>. Due to the different develop progresses of various of web browsers, i2c.ninja only chrome/chromium-cored browsers.</p><p>i2c.ninja is built with</p><ul><li><a href="https://www.naiveui.com">Naive UI</a></li><li><a href="https://www.chartjs.org">Chart.js</a> with <a href="https://nagix.github.io/chartjs-plugin-streaming">chartjs-plugin-streaming</a></li><li><a href="https://vuejs.org/">Vue.js 3</a></li><li><a href="https://vitejs.dev/">Vite</a></li></ul><p>ICON from <a href="https://iconscout.com/icon/usb-1476574">iconscout</a></p><p>Developer: <a href="https://twitter.com/BG5USN">@BG5USN</a></p><h1>Sourcekit ATiic [&#39;\xE6ti:k]</h1><p>Sourcekit\xAE Atiic is a simple tool that provides basic control to <a href="https://en.wikipedia.org/wiki/I%C2%B2C">i\xB2c</a> devices with AT commands in Serial Communication. It got USB-TTL chip at one size and have an I\xB2C bus on the other which could host multiple i\xB2c devices.</p><h3>Serial Port (COM) Specification</h3><ul><li>Baudrate: 115200</li><li>Databits: 8</li><li>Parity: None</li><li>Stopbits: 1</li></ul><h3>i2c Specification</h3><ul><li>Speed: 100KHz</li><li>Voltage: 3.3 V</li></ul><h3>AT Command SET</h3><ul><li><p>Request (TX)</p><ol><li><p>Request should always be an <code>one-line</code> string to the serial port started with <code>AT</code> and ended with <code>&lt;CR&gt;&lt;LF&gt;</code>, aka <code>\\r\\n</code>.</p></li><li><p>The maximum length of a single request is <code>64</code> charactors, including <code>AT</code> and <code>&lt;CR&gt;&lt;LF&gt;</code>.</p></li><li><p>Format:</p></li></ol><ul><li><code>AT+&lt;CMD&gt;&lt;CR&gt;&lt;LF&gt;</code>: Command without Arguments.</li><li><code>AT+&lt;CMD&gt;=&lt;HEX&gt;&lt;CR&gt;&lt;LF&gt;</code>: Command with Arguments got a <code>=</code> to separate <code>&lt;CMD&gt;</code> and <code>&lt;HEX&gt;</code></li></ul><ol start="4"><li><p>The <code>Hex</code> length should always be even, so it can be convert into designated bytes.</p></li><li><p>Case Insensitive and Space is ignored</p></li></ol></li><li><p>Response (RX) is always a <code>three-liner</code> string, containing <code>Echo</code>, <code>Body</code> and <code>Result</code>, each line ended with <code>&lt;CR&gt;&lt;LF&gt;</code>.</p><ol><li>The 1st line, <code>Echo&lt;CR&gt;&lt;LF&gt;</code>, is the request it response to.</li><li>The 2nd line, <code>Body&lt;CR&gt;&lt;LF&gt;</code>, is always in <code>HEX</code> format.</li><li>The 3rd line, <code>Result&lt;CR&gt;&lt;LF&gt;</code>, is neither <code>OK</code> or <code>ERROR</code>.</li></ol></li><li><p><em>CAUTION</em>: Always Send new request after last request in fully responsed with <code>OK\\r\\n</code> or <code>ERROR\\r\\n</code>.</p></li><li><p>Commands:</p><ol><li><strong>AT+SC</strong>: Scan devices for 7-bit addresses</li></ol><p>TX:</p><pre><code>AT+SC
</code></pre><p>RX:</p><pre><code>AT+SC
4476
OK
</code></pre><p>It means it detect i2c devices on address <code>0x44</code> and <code>0x76</code>, all of which are 7-bit address (without W/R bit).</p><ol start="2"><li><strong>AT+TX=<code>DEVICE</code> <code>TX_PAYLOAD</code></strong>: write bytes to devices</li></ol><p><code>DEVICE</code> is the 7-bit address of which ATiic send commands to. <code>TX_PAYLOAD</code> is the bytes you want to send to the device in <code>HEX</code> format.</p><p>TX:</p><pre><code>AT+TX=760603
</code></pre><p>RX:</p><pre><code>AT+TX=760603

OK
</code></pre><p>In the case of sensor <code>SPL06</code> on address <code>0x76</code>, it means write <code>0x03</code> to register at address <code>0x06</code>, which is device soft reset.</p><p>So <em>AT+TX=</em> is aim to write bytes to devices</p><ol start="3"><li><strong>AT+TR=<code>DEVICE</code> <code>TX_PAYLOAD</code> <code>RX_COUNT</code></strong></li></ol><p><code>DEVICE</code> is the 7-bit address of which ATiic send commands to. <code>TX_PAYLOAD</code> is the bytes you want to send to the device in <code>HEX</code> format. <code>RX_COUNT</code> is always 1 Byte (2 character in Hex) indicating how many bytes would be received after <code>TX_PAYLOAD</code> is transmitted.</p><p>TX:</p><pre><code>AT+TR=442c0d06    
</code></pre><p>RX:</p><pre><code>AT+TR=442c0d06
68AAC492F631
OK
</code></pre><p>In the case of sensor <code>SHT30</code> on address <code>0x68</code>, it means read <code>0x06</code> bytes after writing <code>0x2c 0x2d</code> to it. Then the response is <code>0x68 0xAA 0xC4 0x92 0xF6 0x31</code> in hex format.</p><p>So <code>AT+RX=</code> is aim to read registered after write the starter address to the devices.</p><p><em>CAUTION</em>: the last 2 hex character is always considered as <code>RX_COUNT</code>, so <code>TX_PAYLOAD</code> is the hex string between <code>=</code> and <code>RX_COUNT</code>. <code>TX_PAYLOAD</code> could be empty.</p></li></ul>`,15);function u(t,i){return p}const a={render:u};a.__hmrId="/home/agu/gitpool/stc8flash/apps/i2c.ninja/src/assets/about.md";const m=s("<h2>Releases</h2><h3>0.1.2</h3><ul><li>rename <code>AT+DETECT</code> to <code>AT+SC</code> (scan)</li></ul><h3>0.1.1</h3><ul><li>BME280</li></ul><h3>0.1.0</h3><ul><li>SHT30</li><li>SPL06</li></ul>",7);function g(t,i){return m}const l={render:g};l.__hmrId="/home/agu/gitpool/stc8flash/apps/i2c.ninja/src/assets/releases.md";const w={setup(t){return(i,T)=>(r(),n(h,null,[e(o(c),null,{default:d(()=>[e(o(a))]),_:1}),e(o(c),null,{default:d(()=>[e(o(l))]),_:1})],64))}};export{w as default};
